// NeoTravel MVP - Normalize Input
const input = $input.first()?.json || {};
const body = input.body || input || {};
const now = new Date().toISOString();

const message = body.message || body.chatInput || body.text || '';
const sessionId = body.session_id || body.sessionId || body.session || `session_${Date.now()}`;

const context = body.context || {
  session_id: sessionId,
  lead_id: null,
  demande_id: null,
  client: { nom: '', prenom: '', email: '', telephone: '', societe: '', type_client: '' },
  trajet: { depart: '', destination: '', date_depart: '', date_retour: '', heure_depart: '', passagers: 0, type_trajet: '', commentaire: '' },
  quote: { distance_km: null, vehicle: '', price_ht: null, tva: null, price_ttc: null, options: [], pdf_url: '' },
  commercial: { complexe: false, raison: '', commentaire: '' },
  status: { lead_created: false, distance_calculated: false, quote_calculated: false, pdf_generated: false, email_sent: false, commercial_required: false },
  metadata: { source: 'chat', created_at: now.slice(0, 10), normalized_at: now }
};

context.session_id = context.session_id || sessionId;
context.conversation = context.conversation || {};
context.conversation.last_user_message = message;
context.last_update_at = now;

return [{ json: { message, chatInput: message, session_id: sessionId, sessionId, context } }];
